import math
from pathlib import Path

import pytest
import yaml

from astar import a_star

FIXTURES_DIR = Path(__file__).parent / "fixtures"


def _load_fixture(name):
    with open(FIXTURES_DIR / name) as f:
        return yaml.safe_load(f)


def _path_is_valid(graph, path, start, goal):
    if not path or path[0] != start or path[-1] != goal:
        return False
    for u, v in zip(path, path[1:]):
        if v not in graph.get(u, {}):
            return False
    return True


def _path_length(graph, path):
    return sum(graph[u][v] for u, v in zip(path, path[1:]))


def _manhattan(coords, goal):
    gx, gy = coords[goal]

    def h(node):
        x, y = coords[node]
        return abs(x - gx) + abs(y - gy)

    return h


@pytest.mark.parametrize("fixture_name", ["simple.yaml", "grid.yaml"])
def test_finds_optimal_path_with_zero_heuristic(fixture_name):
    data = _load_fixture(fixture_name)
    graph, start, goal = data["graph"], data["start"], data["goal"]

    path, length = a_star(graph, start, goal, lambda node: 0)

    assert length == data["expected_length"]
    assert _path_is_valid(graph, path, start, goal)
    assert _path_length(graph, path) == length


def test_finds_optimal_path_with_admissible_heuristic():
    data = _load_fixture("grid.yaml")
    graph = data["graph"]
    start, goal = data["start"], data["goal"]

    path, length = a_star(graph, start, goal, _manhattan(data["coords"], goal))

    assert length == data["expected_length"]
    assert _path_is_valid(graph, path, start, goal)
    assert _path_length(graph, path) == length


def test_returns_empty_path_when_goal_unreachable():
    data = _load_fixture("disconnected.yaml")
    graph, start, goal = data["graph"], data["start"], data["goal"]

    path, length = a_star(graph, start, goal, lambda node: 0)

    assert path == []
    assert length == math.inf


def test_start_equals_goal():
    graph = {"x": {"y": 1}, "y": {}}

    path, length = a_star(graph, "x", "x", lambda node: 0)

    assert path == ["x"]
    assert length == 0

